{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-pump-update-plus-separator-placeholder-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "success",
  "answers": [
    {
      "summary": "针对当前选中的增压泵（Booster Pump）、分离器（Product Separator）及其相关物流，基于诊断信息为您生成了参数修正与拓扑补全的候选提案。",
      "issues": [
        {
          "description": "增压泵的出口压力目标设定（150 kPa）低于入口压力（200 kPa），并且其效率参数（109%）超出了合理的物理建议范围。",
          "citations": [
            "diag-2",
            "diag-4",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "description": "产品分离器当前被配置为恒压模式，但在设备参数中缺少具体的运行压力目标值。",
          "citations": [
            "diag-3",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        },
        {
          "description": "分离器液相出口尚未连接到任何下游设备或接收终端，导致流程拓扑不完整。",
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ]
    }
  ],
  "proposed_actions": [
    {
      "action_type": "candidate_edit",
      "title": "纠正增压泵出口压力目标并调整效率",
      "target": "pump-13",
      "rationale": "需要修正增压泵不合理的效率参数（109%降至常见默认值75%），并提供出口压力的补全占位符，以确保其高于已知的200 kPa入口压力。",
      "patch": {
        "parameter_updates": {
          "efficiency_percent": 75
        },
        "parameter_placeholders": {
          "outlet_pressure_target_kpa": "__REQUIRED_PRESSURE_GREATER_THAN_200_KPA__"
        }
      },
      "risk_level": "medium",
      "requires_confirmation": true,
      "confidence": 0.95,
      "citations": [
        "diag-2",
        "diag-4",
        "flowdoc-unit-1",
        "flowdoc-stream-1",
        "snapshot-1"
      ]
    },
    {
      "action_type": "candidate_edit",
      "title": "补充气液分离器操作压力目标",
      "target": "separator-10",
      "rationale": "由于产品分离器已配置为 fixed（恒压）模式，需在配置中补充所需的操作压力参数占位符以符合规格约束。",
      "patch": {
        "parameter_placeholders": {
          "operating_pressure_kpa": "__REQUIRED_SEPARATION_PRESSURE__"
        }
      },
      "risk_level": "medium",
      "requires_confirmation": true,
      "confidence": 0.95,
      "citations": [
        "diag-3",
        "flowdoc-unit-2",
        "snapshot-1"
      ]
    },
    {
      "action_type": "candidate_edit",
      "title": "配置分离器液相出口连接",
      "target": "separator-liquid-92",
      "rationale": "由于分离器液相出口存在未连接断点错误，建议重连至实际的下游接收单元或导出终端。",
      "patch": {
        "connection_placeholder": {
          "target_unit_id": "__DOWNSTREAM_CONSUMER_OR_SINK__"
        }
      },
      "risk_level": "high",
      "requires_confirmation": true,
      "confidence": 0.90,
      "citations": [
        "diag-1",
        "diag-5",
        "flowdoc-stream-3",
